func flattenMigrationCenterDiscoveryClientErrors(v interface{}, d *schema.ResourceData, config *transport_tpg.Config) interface{} {
	if v == nil {
		return v
	}
	l := v.([]interface{})
	transformed := make([]interface{}, 0, len(l))
	for _, raw := range l {
		original := raw.(map[string]interface{})
		if len(original) < 1 {
			// Do not include empty json objects coming back from the api
			continue
		}
		transformed = append(transformed, map[string]interface{}{
			"code":    flattenMigrationCenterDiscoveryClientErrorsCode(original["code"], d, config),
			"details": flattenMigrationCenterDiscoveryClientErrorsDetails(original["details"], d, config),
			"message": flattenMigrationCenterDiscoveryClientErrorsMessage(original["message"], d, config),
		})
	}
	return transformed
}
func flattenMigrationCenterDiscoveryClientErrorsCode(v interface{}, d *schema.ResourceData, config *transport_tpg.Config) interface{} {
	// Handles the string fixed64 format
	if strVal, ok := v.(string); ok {
		if intVal, err := tpgresource.StringToFixed64(strVal); err == nil {
			return intVal
		}
	}

	// number values are represented as float64
	if floatVal, ok := v.(float64); ok {
		intVal := int(floatVal)
		return intVal
	}

	return v // let terraform core handle it otherwise
}

